package com.example.finalproject.activities;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.view.View;
import android.view.animation.Animation;
import android.view.animation.AnimationUtils;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ImageButton;
import android.widget.TextView;
import android.widget.Toast;

import com.example.finalproject.R;
import com.example.finalproject.model.GmailSender;
import com.google.firebase.database.DataSnapshot;
import com.google.firebase.database.DatabaseError;
import com.google.firebase.database.DatabaseReference;
import com.google.firebase.database.FirebaseDatabase;
import com.google.firebase.database.ValueEventListener;

public class ForgotActivity extends AppCompatActivity {

    private FirebaseDatabase database;
    private DatabaseReference ref;
    Button btnGetPass;
    ImageButton imgLogin;
    GmailSender Gmail = new GmailSender();
    EditText edt_username, edt_email;

    TextView tvWelcomeTitle;
    Animation animation_et_left, animation_tvHomeTitle;
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_forgot);

        imgLogin = findViewById(R.id.imgLogin_Forgot);
        imgLogin.setOnClickListener(v -> {
            Intent intent = new Intent(ForgotActivity.this, WelcomeActivity.class);
            startActivity(intent);
        });

        tvWelcomeTitle = findViewById(R.id.tvWelcomeTitle);
        animation_tvHomeTitle = AnimationUtils.loadAnimation(this, R.anim.anime_tv);
        tvWelcomeTitle.setAnimation(animation_tvHomeTitle);

        edt_username = findViewById(R.id.edt_username);
        animation_et_left = AnimationUtils.loadAnimation(this,R.anim.anime_et_left);
        edt_username.setAnimation(animation_et_left);

        edt_email = findViewById(R.id.edt_email);
        animation_et_left = AnimationUtils.loadAnimation(this,R.anim.anime_et_left);
        edt_email.setAnimation(animation_et_left);

        btnGetPass = findViewById(R.id.btnGetpass);
        btnGetPass.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                getPass();
                Intent intent = new Intent(ForgotActivity.this, WelcomeActivity.class);
                startActivity(intent);
            }
        });
    }
    public void getPass(){
        database = FirebaseDatabase.getInstance();
        ref = database.getReference("Habit_Tracker").child("Tai_Khoan");

        final String username = edt_username.getText().toString();
        final String gmail = edt_email.getText().toString();

        if (TextUtils.isEmpty(username) || TextUtils.isEmpty(gmail)) {
            Toast.makeText(this, "Vui lòng nhập tên đăng nhập và gmail", Toast.LENGTH_SHORT).show();
            return;
        }
        ref.addListenerForSingleValueEvent(new ValueEventListener() {
            @Override
            public void onDataChange(@NonNull DataSnapshot dataSnapshot) {
                if (dataSnapshot.exists()) {
                    for (DataSnapshot taiKhoanSnapshot : dataSnapshot.getChildren()) {
                        String currentUsername = taiKhoanSnapshot.child("username").getValue(String.class);
                        String currentGmail = taiKhoanSnapshot.child("gmail").getValue(String.class);
                        if (username.equals(currentUsername) && gmail.equals(currentGmail)) {
                            String currentPassword = taiKhoanSnapshot.child("password").getValue(String.class);
                            String senderEmail = "01215165330asd@gmail.com"; // Địa chỉ Gmail của bạn
                            String senderPassword = "uwcpdnjcsxhchtcv"; // Mật khẩu Gmail của bạn
                            String recipientEmail = gmail; // Địa chỉ Gmail của người nhận
                            String subject = "Gửi lại mật khẩu";
                            String message = "Password của bạn: " + currentPassword;
                            Gmail.sendEmail(senderEmail, senderPassword, recipientEmail, subject, message);
                            return;
                        }
                    }
                    Toast.makeText(ForgotActivity.this, "Tài khoản và  gmail không khớp với nhau", Toast.LENGTH_SHORT).show();
                }
            }
            @Override
            public void onCancelled(@NonNull DatabaseError databaseError) {
                // Xử lý lỗi khi đọc dữ liệu từ Firebase
                Toast.makeText(ForgotActivity.this, "Lỗi khi đọc dữ liệu từ Firebase", Toast.LENGTH_SHORT).show();
            }
        });
    }
}

package com.example.finalproject.activities;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.view.View;
import android.view.animation.Animation;
import android.view.animation.AnimationUtils;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ImageButton;
import android.widget.TextView;
import android.widget.Toast;

import com.example.finalproject.R;
import com.example.finalproject.model.HabitDatabaseHelper;
import com.example.finalproject.model.GmailSender;

public class ForgotActivity extends AppCompatActivity {

    private HabitDatabaseHelper databaseHelper;
    Button btnGetPass;
    ImageButton imgLogin;
    GmailSender Gmail = new GmailSender();
    EditText edt_username, edt_email;

    TextView tvWelcomeTitle;
    Animation animation_et_left, animation_tvHomeTitle;
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_forgot);

        imgLogin = findViewById(R.id.imgLogin_Forgot);
        imgLogin.setOnClickListener(v -> {
            Intent intent = new Intent(ForgotActivity.this, WelcomeActivity.class);
            startActivity(intent);
        });

        tvWelcomeTitle = findViewById(R.id.tvWelcomeTitle);
        animation_tvHomeTitle = AnimationUtils.loadAnimation(this, R.anim.anime_tv);
        tvWelcomeTitle.setAnimation(animation_tvHomeTitle);

        edt_username = findViewById(R.id.edt_username);
        animation_et_left = AnimationUtils.loadAnimation(this,R.anim.anime_et_left);
        edt_username.setAnimation(animation_et_left);

        edt_email = findViewById(R.id.edt_email);
        animation_et_left = AnimationUtils.loadAnimation(this,R.anim.anime_et_left);
        edt_email.setAnimation(animation_et_left);

        btnGetPass = findViewById(R.id.btnGetpass);
        btnGetPass.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                getPass();
                Intent intent = new Intent(ForgotActivity.this, WelcomeActivity.class);
                startActivity(intent);
            }
        });
    }
    public void getPass(){
        databaseHelper = HabitDatabaseHelper.getInstance(this);

        final String username = edt_username.getText().toString();
        final String gmail = edt_email.getText().toString();

        if (TextUtils.isEmpty(username) || TextUtils.isEmpty(gmail)) {
            Toast.makeText(this, "Vui lòng nhập tên đăng nhập và gmail", Toast.LENGTH_SHORT).show();
            return;
        }

        String accountId = databaseHelper.getAccountIdByUsernameAndGmail(username, gmail);
        if (accountId == null) {
            Toast.makeText(ForgotActivity.this, "Tài khoản và  gmail không khớp với nhau", Toast.LENGTH_SHORT).show();
            return;
        }

        String currentPassword = databaseHelper.getAccountById(accountId).getPassword();
        String senderEmail = "01215165330asd@gmail.com";
        String senderPassword = "uwcpdnjcsxhchtcv";
        String recipientEmail = gmail;
        String subject = "Gửi lại mật khẩu";
        String message = "Password của bạn: " + currentPassword;
        Gmail.sendEmail(senderEmail, senderPassword, recipientEmail, subject, message);
    }
}

package com.example.finalproject.activities;

import androidx.appcompat.app.AppCompatActivity;

import android.app.AlarmManager;
import android.app.NotificationChannel;
import android.app.NotificationManager;
import android.app.PendingIntent;
import android.content.Context;
import android.content.Intent;
import android.os.Build;
import android.os.Bundle;
import android.util.Log;
import android.view.View;
import android.widget.AdapterView;
import android.widget.ImageButton;
import android.widget.ListView;
import android.widget.TextView;

import com.example.finalproject.R;
import com.example.finalproject.model.Account;
import com.example.finalproject.model.Habit;
import com.example.finalproject.model.HabitAction;
import com.example.finalproject.model.HabitDatabaseHelper;
import com.example.finalproject.model.ListviewHomeTest;
import com.example.finalproject.model.MyBroadcastReceiver;
import com.example.finalproject.ui.LisviewHomeTestAdapter;
import com.google.android.material.floatingactionbutton.FloatingActionButton;
import com.harrywhewell.scrolldatepicker.DayScrollDatePicker;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.text.SimpleDateFormat;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.Calendar;
import java.util.Date;
import java.util.Locale;
import java.util.List;

public class Home_Activity extends AppCompatActivity {
    private HabitDatabaseHelper databaseHelper;
    private Account acc = new Account();
    private DayScrollDatePicker mPicker;
    private TextView currentDay;
    private String idUser;
    ListView listHome;
    ArrayList<ListviewHomeTest> arrayListHome;
    LisviewHomeTestAdapter adapterHome;
    FloatingActionButton btnNew; // Đã sửa: Phải là FloatingActionButton
    ImageButton ibGraph, ibMusic, ibClock, ibSettings;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_home);

        databaseHelper = HabitDatabaseHelper.getInstance(this);

        // Nhận dữ liệu an toàn
        Bundle b = getIntent().getExtras();
        if (b != null && b.getSerializable("user_account") != null) {
            acc = (Account) b.getSerializable("user_account");
        }

        idUser = getIntent().getStringExtra("idTaiKhoan");
        if (idUser == null && acc != null) {
            idUser = databaseHelper.getAccountIdByUsernameAndPassword(acc.getUsername(), acc.getPassword());
        }

        currentDay = findViewById(R.id.txtCurrentDay);
        if (currentDay != null) {
            DateTimeFormatter formatter = DateTimeFormatter.ofPattern("dd-MM-yyyy");
            currentDay.setText(LocalDateTime.now().format(formatter));
        }

        mPicker = findViewById(R.id.day_date_picker);
        if (mPicker != null) {
            mPicker.setStartDate(1, 1, 2024);
            mPicker.setEndDate(31, 12, 2025);
        }

        listHome = findViewById(R.id.lvHome);
        arrayListHome = new ArrayList<>();
        adapterHome = new LisviewHomeTestAdapter(arrayListHome, this, R.layout.list_item_home, idUser);
        listHome.setAdapter(adapterHome);

        listHome.setOnItemClickListener((parent, view, position, id) -> {
            Intent intent = new Intent(Home_Activity.this, ProgressActivity.class);
            Bundle bundle = new Bundle();
            bundle.putSerializable("user_account", acc);
            intent.putExtras(bundle);
            intent.putExtra("idThoiQuen", arrayListHome.get(position).getHabitId());
            intent.putExtra("idTaiKhoan", idUser);
            startActivity(intent);
        });

        btnNew = findViewById(R.id.btnNew); 
        btnNew.setOnClickListener(v -> {
            Intent intent = new Intent(Home_Activity.this, Create_habit.class);
            Bundle bundle = new Bundle();
            bundle.putSerializable("user_account", acc);
            intent.putExtra("idTaiKhoan", idUser);
            intent.putExtras(bundle);
            startActivity(intent);
        });

        setupBottomNav();
        notification();
    }

    @Override
    protected void onResume() {
        super.onResume();
        if (idUser != null) {
            getListHabit();
            getReminder();
        }
    }

    private void setupBottomNav() {
        ibGraph = findViewById(R.id.ib_graph);
        ibMusic = findViewById(R.id.ib_music);
        ibClock = findViewById(R.id.ib_clock);
        ibSettings = findViewById(R.id.ib_settings);

        View.OnClickListener navListener = v -> {
            Class<?> target = null;
            if (v.getId() == R.id.ib_graph) target = Progress_total.class;
            else if (v.getId() == R.id.ib_music) target = SongsActivity.class;
            else if (v.getId() == R.id.ib_clock) target = Pomorodo.class;
            else if (v.getId() == R.id.ib_settings) target = Setting.class;

            if (target != null) {
                Intent i = new Intent(Home_Activity.this, target);
                Bundle bundle = new Bundle();
                bundle.putSerializable("user_account", acc);
                i.putExtra("idTaiKhoan", idUser);
                i.putExtras(bundle);
                startActivity(i);
            }
        };

        if (ibGraph != null) ibGraph.setOnClickListener(navListener);
        if (ibMusic != null) ibMusic.setOnClickListener(navListener);
        if (ibClock != null) ibClock.setOnClickListener(navListener);
        if (ibSettings != null) ibSettings.setOnClickListener(navListener);
    }

    public void getListHabit() {
        if (idUser == null) return;
        arrayListHome.clear();
        List<Habit> habits = databaseHelper.getHabitsByUser(idUser);
        for (Habit habit : habits) {
            String habitId = habit.getHabitId();
            double target = calculateTarget(habit.getMucTieu(), habit.getKhoangThoiGian());
            double doing = getHistoryData(databaseHelper.getHabitActions(idUser, habitId));

            double progress = (target > 0) ? (doing * 100.0 / target) : 0;
            String doneText = String.format(Locale.getDefault(), "%.1f/%.1f %s", doing, target, habit.getDonVi());

            ListviewHomeTest item = new ListviewHomeTest(
                habitId, habit.getTen(), habit.getThoiDiem(), 
                habit.getThoiGianNhacNho(), doneText, (int) Math.min(100, progress), 
                habit.getDonViTang(), target, habit.getTrangThai(), doing
            );
            arrayListHome.add(item);
        }
        adapterHome.notifyDataSetChanged();
    }

    public double calculateTarget(double target, String period) {
        if (period == null) return target;
        double result = target;
        if (period.equalsIgnoreCase("Week")) result = target / 7.0;
        else if (period.equalsIgnoreCase("Month")) result = target / 30.0;
        return new BigDecimal(result).setScale(1, RoundingMode.HALF_UP).doubleValue();
    }

    public double getHistoryData(List<HabitAction> actions) {
        double result = 0;
        for (HabitAction action : actions) {
            if (databaseHelper.isToday(action.getActionTime())) result += action.getValue();
        }
        return result;
    }

    public void getReminder() {
        if (idUser == null) return;
        for (Habit habit : databaseHelper.getHabitsByUser(idUser)) {
            Calendar cal = databaseHelper.parseReminderTime(habit.getThoiGianNhacNho());
            setTimer(cal.get(Calendar.HOUR_OF_DAY), cal.get(Calendar.MINUTE), habit.getLoiNhacNho());
        }
    }

    private void setTimer(int hour, int minute, String message) {
        AlarmManager alarmManager = (AlarmManager) getSystemService(Context.ALARM_SERVICE);
        Calendar cal_alarm = Calendar.getInstance();
        cal_alarm.set(Calendar.HOUR_OF_DAY, hour);
        cal_alarm.set(Calendar.MINUTE, minute);
        cal_alarm.set(Calendar.SECOND, 0);

        if (cal_alarm.before(Calendar.getInstance())) cal_alarm.add(Calendar.DATE, 1);

        Intent i = new Intent(this, MyBroadcastReceiver.class);
        i.putExtra("message", message);
        int requestCode = (int) System.currentTimeMillis(); 
        PendingIntent pendingIntent = PendingIntent.getBroadcast(this, requestCode, i, PendingIntent.FLAG_IMMUTABLE);
        if (alarmManager != null) alarmManager.setExactAndAllowWhileIdle(AlarmManager.RTC_WAKEUP, cal_alarm.getTimeInMillis(), pendingIntent);
    }

    private void notification() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            NotificationChannel channel = new NotificationChannel("Notify", "Habit Reminders", NotificationManager.IMPORTANCE_DEFAULT);
            NotificationManager manager = getSystemService(NotificationManager.class);
            if (manager != null) manager.createNotificationChannel(channel);
        }
    }
}

package com.example.finalproject.activities;

import androidx.appcompat.app.AlertDialog;
import androidx.appcompat.app.AppCompatActivity;

import android.app.AlarmManager;
import android.app.NotificationChannel;
import android.app.NotificationManager;
import android.app.PendingIntent;
import android.content.Context;
import android.content.Intent;
import android.os.Build;
import android.os.Bundle;
import android.util.Log;
import android.view.View;
import android.widget.AdapterView;
import android.widget.ImageButton;
import android.widget.ListView;
import android.widget.TextView;
import android.widget.Toast;

import com.example.finalproject.R;
import com.example.finalproject.model.Account;
import com.example.finalproject.model.Habit;
import com.example.finalproject.model.HabitAction;
import com.example.finalproject.model.HabitDatabaseHelper;
import com.example.finalproject.model.ListviewHomeTest;
import com.example.finalproject.model.MyBroadcastReceiver;
import com.example.finalproject.ui.LisviewHomeTestAdapter;
import com.google.android.material.floatingactionbutton.FloatingActionButton;
import com.harrywhewell.scrolldatepicker.DayScrollDatePicker;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.text.SimpleDateFormat;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.Calendar;
import java.util.Date;
import java.util.Locale;
import java.util.List;

public class Home_Activity extends AppCompatActivity {
    private HabitDatabaseHelper databaseHelper;
    private Account acc = new Account();
    private DayScrollDatePicker mPicker;
    private TextView currentDay;
    private String idUser;
    ListView listHome;
    ArrayList<ListviewHomeTest> arrayListHome;
    LisviewHomeTestAdapter adapterHome;
    FloatingActionButton btnNew; // Đã sửa: Phải là FloatingActionButton
    ImageButton ibGraph, ibMusic, ibClock, ibSettings;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_home);

        databaseHelper = HabitDatabaseHelper.getInstance(this);

        // Nhận dữ liệu an toàn
        Bundle b = getIntent().getExtras();
        if (b != null && b.getSerializable("user_account") != null) {
            acc = (Account) b.getSerializable("user_account");
        }

        idUser = getIntent().getStringExtra("idTaiKhoan");
        if (idUser == null && acc != null) {
            idUser = databaseHelper.getAccountIdByUsernameAndPassword(acc.getUsername(), acc.getPassword());
        }

        currentDay = findViewById(R.id.txtCurrentDay);
        if (currentDay != null) {
            DateTimeFormatter formatter = DateTimeFormatter.ofPattern("dd-MM-yyyy");
            currentDay.setText(LocalDateTime.now().format(formatter));
        }

        mPicker = findViewById(R.id.day_date_picker);
        if (mPicker != null) {
            mPicker.setStartDate(1, 1, 2024);
            mPicker.setEndDate(31, 12, 2025);
        }

        listHome = findViewById(R.id.lvHome);
        arrayListHome = new ArrayList<>();
        adapterHome = new LisviewHomeTestAdapter(arrayListHome, this, R.layout.list_item_home, idUser);
        listHome.setAdapter(adapterHome);

        listHome.setOnItemClickListener((parent, view, position, id) -> {
            ListviewHomeTest item = arrayListHome.get(position);
            showHabitOptions(item);
        });

        btnNew = findViewById(R.id.btnNew); 
        btnNew.setOnClickListener(v -> {
            Intent intent = new Intent(Home_Activity.this, Create_habit.class);
            Bundle bundle = new Bundle();
            bundle.putSerializable("user_account", acc);
            intent.putExtra("idTaiKhoan", idUser);
            intent.putExtras(bundle);
            startActivity(intent);
        });

        setupBottomNav();
        notification();
    }

    @Override
    protected void onResume() {
        super.onResume();
        if (idUser != null) {
            getListHabit();
            getReminder();
        }
    }

    private void setupBottomNav() {
        ibGraph = findViewById(R.id.ib_graph);
        ibMusic = findViewById(R.id.ib_music);
        ibClock = findViewById(R.id.ib_clock);
        ibSettings = findViewById(R.id.ib_settings);

        View.OnClickListener navListener = v -> {
            Class<?> target = null;
            if (v.getId() == R.id.ib_graph) target = Progress_total.class;
            else if (v.getId() == R.id.ib_music) target = SongsActivity.class;
            else if (v.getId() == R.id.ib_clock) target = Pomorodo.class;
            else if (v.getId() == R.id.ib_settings) target = Setting.class;

            if (target != null) {
                Intent i = new Intent(Home_Activity.this, target);
                Bundle bundle = new Bundle();
                bundle.putSerializable("user_account", acc);
                i.putExtra("idTaiKhoan", idUser);
                i.putExtras(bundle);
                startActivity(i);
            }
        };

        if (ibGraph != null) ibGraph.setOnClickListener(navListener);
        if (ibMusic != null) ibMusic.setOnClickListener(navListener);
        if (ibClock != null) ibClock.setOnClickListener(navListener);
        if (ibSettings != null) ibSettings.setOnClickListener(navListener);
    }

    public void getListHabit() {
        if (idUser == null) return;
        arrayListHome.clear();
        List<Habit> habits = databaseHelper.getHabitsByUser(idUser);
        for (Habit habit : habits) {
            String habitId = habit.getHabitId();
            double target = calculateTarget(habit.getMucTieu(), habit.getKhoangThoiGian());
            double doing = getHistoryData(databaseHelper.getHabitActions(idUser, habitId));

            double progress = (target > 0) ? (doing * 100.0 / target) : 0;
            String doneText = String.format(Locale.getDefault(), "%.1f/%.1f %s", doing, target, habit.getDonVi());

            ListviewHomeTest item = new ListviewHomeTest(
                habitId, habit.getTen(), habit.getThoiDiem(), 
                habit.getThoiGianNhacNho(), doneText, (int) Math.min(100, progress), 
                habit.getDonViTang(), target, habit.getTrangThai(), doing
            );
            arrayListHome.add(item);
        }
        adapterHome.notifyDataSetChanged();
    }

    public double calculateTarget(double target, String period) {
        if (period == null) return target;
        double result = target;
        if (period.equalsIgnoreCase("Week")) result = target / 7.0;
        else if (period.equalsIgnoreCase("Month")) result = target / 30.0;
        return new BigDecimal(result).setScale(1, RoundingMode.HALF_UP).doubleValue();
    }

    public double getHistoryData(List<HabitAction> actions) {
        double result = 0;
        for (HabitAction action : actions) {
            if (databaseHelper.isToday(action.getActionTime())) result += action.getValue();
        }
        return result;
    }

    private void showHabitOptions(ListviewHomeTest item) {
        if (item == null || idUser == null) return;

        String[] options = {"Xem chi tiết", "Chỉnh sửa", "Xoá"};
        new AlertDialog.Builder(this)
                .setTitle(item.getNameHabit())
                .setItems(options, (dialog, which) -> {
                    if (which == 0) {
                        Intent intent = new Intent(Home_Activity.this, ProgressActivity.class);
                        Bundle bundle = new Bundle();
                        bundle.putSerializable("user_account", acc);
                        intent.putExtras(bundle);
                        intent.putExtra("idThoiQuen", item.getHabitId());
                        intent.putExtra("idTaiKhoan", idUser);
                        startActivity(intent);
                    } else if (which == 1) {
                        Intent intent = new Intent(Home_Activity.this, Edit_habit.class);
                        Bundle bundle = new Bundle();
                        bundle.putSerializable("user_account", acc);
                        intent.putExtras(bundle);
                        intent.putExtra("idThoiQuen", item.getHabitId());
                        intent.putExtra("idTaiKhoan", idUser);
                        startActivity(intent);
                    } else if (which == 2) {
                        new AlertDialog.Builder(this)
                                .setTitle("Xác nhận xoá")
                                .setMessage("Bạn có chắc muốn xoá thói quen này không?")
                                .setPositiveButton("Xoá", (d, w) -> {
                                    databaseHelper.deleteHabit(idUser, item.getHabitId());
                                    getListHabit();
                                    Toast.makeText(this, "Đã xoá thói quen", Toast.LENGTH_SHORT).show();
                                })
                                .setNegativeButton("Huỷ", null)
                                .show();
                    }
                })
                .show();
    }

    public void getReminder() {
        if (idUser == null) return;
        for (Habit habit : databaseHelper.getHabitsByUser(idUser)) {
            Calendar cal = databaseHelper.parseReminderTime(habit.getThoiGianNhacNho());
            setTimer(cal.get(Calendar.HOUR_OF_DAY), cal.get(Calendar.MINUTE), habit.getLoiNhacNho());
        }
    }

    private void setTimer(int hour, int minute, String message) {
        AlarmManager alarmManager = (AlarmManager) getSystemService(Context.ALARM_SERVICE);
        Calendar cal_alarm = Calendar.getInstance();
        cal_alarm.set(Calendar.HOUR_OF_DAY, hour);
        cal_alarm.set(Calendar.MINUTE, minute);
        cal_alarm.set(Calendar.SECOND, 0);

        if (cal_alarm.before(Calendar.getInstance())) cal_alarm.add(Calendar.DATE, 1);

        Intent i = new Intent(this, MyBroadcastReceiver.class);
        i.putExtra("message", message);
        int requestCode = (int) System.currentTimeMillis(); 
        PendingIntent pendingIntent = PendingIntent.getBroadcast(this, requestCode, i, PendingIntent.FLAG_IMMUTABLE);
        if (alarmManager != null) alarmManager.setExactAndAllowWhileIdle(AlarmManager.RTC_WAKEUP, cal_alarm.getTimeInMillis(), pendingIntent);
    }

    private void notification() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            NotificationChannel channel = new NotificationChannel("Notify", "Habit Reminders", NotificationManager.IMPORTANCE_DEFAULT);
            NotificationManager manager = getSystemService(NotificationManager.class);
            if (manager != null) manager.createNotificationChannel(channel);
        }
    }
}

