                        String ngayKetThuc = snapshot.child("ThoiGianKetThuc").getValue(String.class);
                        edt_end_term.setText(ngayKetThuc);
                        Long mucTieu = snapshot.child("MucTieu").getValue(Long.class);
                        edt_goal.setText(mucTieu.toString());
