    public void getDetailHabit(String idHabit, String idTaiKhoan) {
        TextView tvDetail = (TextView) findViewById(R.id.tvDetail);
        txtDIM = (TextView) findViewById(R.id.tvDoneinMonth);
        txtTTD = (TextView) findViewById(R.id.tvTotalDone);
        txtVTT = (TextView) findViewById(R.id.tvVolTotal);
        txtCS = (TextView) findViewById(R.id.tvCurrentStreak);

        databaseHelper = HabitDatabaseHelper.getInstance(this);
        try {
            Habit currentHabit = databaseHelper.getHabit(idTaiKhoan, idHabit);
            if (currentHabit == null) {
                Toast.makeText(ProgressActivity.this, "Không tìm thấy dữ liệu", Toast.LENGTH_SHORT).show();
                return;
            }

            Arrays.fill(perfectArr, 0);
            List<HabitAction> actions = databaseHelper.getHabitActions(idTaiKhoan, idHabit);
            for (HabitAction action : actions) {
                if (databaseHelper.isInCurrentMonth(action.getActionTime())) {
                    Calendar calendar = databaseHelper.parseActionTime(action.getActionTime());
                    if (calendar != null) {
                        perfectArr[calendar.get(Calendar.DAY_OF_MONTH)] = 1;
                    }
                }
            }

            tvDetail.setText(currentHabit.getTen());
            txtTTD.setText(databaseHelper.getTotalDaysWithProgress(idTaiKhoan, idHabit) + " Days");
            txtVTT.setText(String.format("%.1f", databaseHelper.getTotalProgress(idTaiKhoan, idHabit)) + " " + currentHabit.getDonVi());
            txtDIM.setText(databaseHelper.getDoneInCurrentMonth(idTaiKhoan, idHabit) + " Days");
            txtCS.setText(getCurrentSteak() + " Days");
        } catch (Exception e) {
            Toast.makeText(ProgressActivity.this, e.toString() + "\n", Toast.LENGTH_LONG).show();
            Log.d("Error", e.toString());
        }
    }

    public void inforHabit(String idHabit, String idTaiKhoan) {
