        EditText edt_period = (EditText) dialog.findViewById(R.id.edt_period);
        ImageView img_close = (ImageView) dialog.findViewById(R.id.img_close);

        Habit currentHabit = databaseHelper.getHabit(idTaiKhoan, idHabit);
        if (currentHabit != null) {
            edt_name.setText(currentHabit.getTen());
            edt_decription.setText(currentHabit.getMoTa());
            edt_unit_increase.setText(String.valueOf(currentHabit.getDonViTang()));
