        this.section = section;
    }

    public double getDonViTang() {
        return donViTang;
    }

    public void setDonViTang(double donViTang) {
        this.donViTang = donViTang;
    }

    public String getHabitId() {
        return habitId;
    }

    public void setHabitId(String habitId) {
        this.habitId = habitId;
    }

    public String getNameHabit() {
        return nameHabit;
    }

    public void setNameHabit(String nameHabit) {
        this.nameHabit = nameHabit;
    }

    public String getTimeHabit() {
        return timeHabit;
    }

    public void setTimeHabit(String timeHabit) {
        this.timeHabit = timeHabit;
    }

    public String getDoneProgress() {
        return doneProgress;
    }
    public int getDone() {return done;}

    public void setDoneProgress(String doneProgress) {
        this.doneProgress = doneProgress;
    }
}

package com.example.finalproject.model;

import java.io.Serializable;

public class ListviewHomeTest implements Serializable {
    private final String habitId;
    private String nameHabit;
    private String section;
    private String timeHabit;
    private String doneProgress;
    private int done;
    private double donViTang;
    private double target;
    private String status;
    private Double doing;

    public ListviewHomeTest(String habitID, String nameHabit, String section, String timeHabit, String doneProgress, int done, double donVi, double target, String status, Double doing) {
        this.habitId = habitID;
        this.nameHabit = nameHabit;
        this.section = section;
        this.timeHabit = timeHabit;
        this.doneProgress = doneProgress;
        this.done = done;
        this.donViTang = donVi;
        this.target = target;
        this.status = status;
        this.doing = doing;
    }

    public String getHabitId() { return habitId; }
    public String getNameHabit() { return nameHabit; }
    public String getSection() { return section; }
    public String getTimeHabit() { return timeHabit; }
    public String getDoneProgress() { return doneProgress; }
    public int getDone() { return done; }
    public double getDonViTang() { return donViTang; }
    public double getTarget() { return target; }
    public String getStatus() { return status; }
    public Double getDoing() { return doing; }

    public void setStatus(String status) { this.status = status; }
    public void setDoing(Double doing) { this.doing = doing; }
    public void setSection(String section) { this.section = section; }
    public void setDonViTang(double donViTang) { this.donViTang = donViTang; }
    public void setTarget(double target) { this.target = target; }
    public void setTimeHabit(String timeHabit) { this.timeHabit = timeHabit; }
    public void setDoneProgress(String doneProgress) { this.doneProgress = doneProgress; }
    public void setDone(int done) { this.done = done; }
    public void setNameHabit(String nameHabit) { this.nameHabit = nameHabit; }
}

package com.example.finalproject.ui;

import android.app.Activity;
import android.content.Context;
import android.graphics.Color;
import android.view.View;
import android.view.ViewGroup;
import android.widget.AdapterView;
import android.widget.ArrayAdapter;
import android.widget.ImageButton;
import android.widget.ListView;
import android.widget.ListView;
import android.widget.ProgressBar;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;

import com.example.finalproject.R;
import com.example.finalproject.activities.Home_Activity;
import com.example.finalproject.activities.MainActivity;
import com.example.finalproject.model.ListviewHomeTest;
import com.google.firebase.database.DatabaseReference;
import com.google.firebase.database.FirebaseDatabase;

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;

public class LisviewHomeTestAdapter extends ArrayAdapter<ListviewHomeTest> {
    Activity context;
    int resourcedId;
    private ArrayList<ListviewHomeTest> listviewHomeTestsArrayList;
    private FirebaseDatabase database;
    private DatabaseReference ref;
    private String idUser = "User001";

    public LisviewHomeTestAdapter(ArrayList<ListviewHomeTest> listviewHomeTestsArrayList, Activity context, int resourceID) {
        super(context, resourceID, listviewHomeTestsArrayList);
        this.listviewHomeTestsArrayList = listviewHomeTestsArrayList;
        this.context = context;
        this.resourcedId = resourceID;
    }
    @NonNull
    @Override
    public View getView(int position, View convertView, ViewGroup parent) {
        if (convertView == null)
        {
            convertView = context.getLayoutInflater().inflate(resourcedId,null);
        }
        TextView nameHabit = (TextView) convertView.findViewById(R.id.tvHomeListTitle);
        TextView section = (TextView) convertView.findViewById(R.id.tvHomeListSection);
        TextView timeHabit = (TextView) convertView.findViewById(R.id.tvHomeListTime);
        TextView doneProgress = (TextView) convertView.findViewById(R.id.tvDoneProgress);
        ProgressBar progressBar = (ProgressBar) convertView.findViewById(R.id.pbHomeListProgress);

        ListviewHomeTest listviewHomeTest = listviewHomeTestsArrayList.get(position);
        nameHabit.setText(listviewHomeTest.getNameHabit());
        section.setText((listviewHomeTest.getStatus().equals("Đã hoàn thành")) ? "Đã hoàn thành" : listviewHomeTest.getSection());
        timeHabit.setText(listviewHomeTest.getTimeHabit());
        doneProgress.setText(listviewHomeTest.getDoneProgress());
        progressBar.setProgress(listviewHomeTest.getDone());

        ImageButton ibPlus = (ImageButton) convertView.findViewById(R.id.ibHomeListPlus);
        ImageButton ibMinus = (ImageButton) convertView.findViewById(R.id.ibHomeListMinus);
        ibPlus.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                if(listviewHomeTest.getStatus().equals("Đã hoàn thành"))
                    Toast.makeText(context,"Bạn không thể cập nhật tiến độ",Toast.LENGTH_SHORT).show();
                else
                {
                    getConnection(idUser, listviewHomeTest.getHabitId());
                    increaseData(listviewHomeTestsArrayList.get(position).getDonViTang());
                }
            }
        });
        ibMinus.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                if(listviewHomeTest.getStatus().equals("Đã hoàn thành"))
                    Toast.makeText(context,"Bạn không thể cập nhật tiến độ",Toast.LENGTH_SHORT).show();
                else if (listviewHomeTest.getDoing() <= 0)
                    Toast.makeText(context,"Bạn không thể cập nhật tiến độ",Toast.LENGTH_SHORT).show();
                else
                {
                    getConnection(idUser, listviewHomeTest.getHabitId());
                    decreaseData(listviewHomeTestsArrayList.get(position).getDonViTang());
                }
            }
        });

        return convertView;
    }
    public void getConnection(String idUser, String idHabit)
    {
        database = FirebaseDatabase.getInstance();
        ref = database.getReference("Habit_Tracker").child("Du_Lieu").child(idUser).child(idHabit).child("ThoiGianThucHien");
    }
    public void increaseData(double number)
    {
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("dd-MM-yyyy h:mm:ssa");
        String parsedDateTime = LocalDateTime.now().format(formatter);
        ref.child(parsedDateTime).setValue(number);
    }
    public void decreaseData(double number)
    {
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("dd-MM-yyyy h:mm:ssa");
        String parsedDateTime = LocalDateTime.now().format(formatter);
        ref.child(parsedDateTime).setValue(-number);
    }
}

package com.example.finalproject.ui;

import android.app.Activity;
import android.content.Context;
import android.graphics.Color;
import android.view.View;
import android.view.ViewGroup;
import android.widget.AdapterView;
import android.widget.ArrayAdapter;
import android.widget.ImageButton;
import android.widget.ListView;
import android.widget.ListView;
import android.widget.ProgressBar;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;

import com.example.finalproject.R;
import com.example.finalproject.activities.Home_Activity;
import com.example.finalproject.activities.MainActivity;
import com.example.finalproject.model.ListviewHomeTest;
import com.example.finalproject.model.HabitDatabaseHelper;

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;

public class LisviewHomeTestAdapter extends ArrayAdapter<ListviewHomeTest> {
    Activity context;
    int resourcedId;
    private ArrayList<ListviewHomeTest> listviewHomeTestsArrayList;
    private HabitDatabaseHelper databaseHelper;
    private String idUser;

    public LisviewHomeTestAdapter(ArrayList<ListviewHomeTest> listviewHomeTestsArrayList, Activity context, int resourceID, String idUser) {
        super(context, resourceID, listviewHomeTestsArrayList);
        this.listviewHomeTestsArrayList = listviewHomeTestsArrayList;
        this.context = context;
        this.resourcedId = resourceID;
        this.idUser = idUser;
        this.databaseHelper = HabitDatabaseHelper.getInstance(context);
    }
    @NonNull
    @Override
    public View getView(int position, View convertView, ViewGroup parent) {
        if (convertView == null)
        {
            convertView = context.getLayoutInflater().inflate(resourcedId,null);
        }
        TextView nameHabit = (TextView) convertView.findViewById(R.id.tvHomeListTitle);
        TextView section = (TextView) convertView.findViewById(R.id.tvHomeListSection);
        TextView timeHabit = (TextView) convertView.findViewById(R.id.tvHomeListTime);
        TextView doneProgress = (TextView) convertView.findViewById(R.id.tvDoneProgress);
        ProgressBar progressBar = (ProgressBar) convertView.findViewById(R.id.pbHomeListProgress);

        ListviewHomeTest listviewHomeTest = listviewHomeTestsArrayList.get(position);
        nameHabit.setText(listviewHomeTest.getNameHabit());
        section.setText((listviewHomeTest.getStatus().equals("Đã hoàn thành")) ? "Đã hoàn thành" : listviewHomeTest.getSection());
        timeHabit.setText(listviewHomeTest.getTimeHabit());
        doneProgress.setText(listviewHomeTest.getDoneProgress());
        progressBar.setProgress(listviewHomeTest.getDone());

        ImageButton ibPlus = (ImageButton) convertView.findViewById(R.id.ibHomeListPlus);
        ImageButton ibMinus = (ImageButton) convertView.findViewById(R.id.ibHomeListMinus);
        ibPlus.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                if(listviewHomeTest.getStatus().equals("Đã hoàn thành"))
                    Toast.makeText(context,"Bạn không thể cập nhật tiến độ",Toast.LENGTH_SHORT).show();
                else
                {
                    increaseData(listviewHomeTestsArrayList.get(position), listviewHomeTestsArrayList.get(position).getDonViTang());
                }
            }
        });
        ibMinus.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                if(listviewHomeTest.getStatus().equals("Đã hoàn thành"))
                    Toast.makeText(context,"Bạn không thể cập nhật tiến độ",Toast.LENGTH_SHORT).show();
                else if (listviewHomeTest.getDoing() <= 0)
                    Toast.makeText(context,"Bạn không thể cập nhật tiến độ",Toast.LENGTH_SHORT).show();
                else
                {
                    decreaseData(listviewHomeTestsArrayList.get(position), listviewHomeTestsArrayList.get(position).getDonViTang());
                }
            }
        });

        return convertView;
    }
    public void increaseData(ListviewHomeTest item, double number)
    {
        databaseHelper.addHabitAction(idUser, item.getHabitId(), number);
        refreshItem(item, number);
    }
    public void decreaseData(ListviewHomeTest item, double number)
    {
        databaseHelper.addHabitAction(idUser, item.getHabitId(), -number);
        refreshItem(item, -number);
    }

    private void refreshItem(ListviewHomeTest item, double delta) {
        double doing = Math.max(0, item.getDoing() + delta);
        double target = item.getTarget();
        item.setDoing(doing);
        item.setDoneProgress(String.format("%.1f/%.1f %s", doing, target, item.getDoneProgress().split(" ")[1]));
        item.setDone((int) Math.ceil(doing * 100.0 / target));
        notifyDataSetChanged();
    }
}
